#include<bits/stdc++.h>
using namespace std;
int a,b,t;
int x[500010],y[500010],w[500010],s[500010];
struct node
{
    int w,s;
    bool operator<(const node&b)const
    {
        return w<b.w;
    }
}v[500010];
bool check(int x)
{
    int j=1;
    priority_queue<int> q;
    for(int i=1;i<=a;i++)
    {
        while(j<=t&&v[j].w<::x[i])
        {
            q.push(v[j].s);
            j++;
        }
        for(int k=1;k<=x&&!q.empty();k++)
        {
            q.pop();
        }
    }
    for(;j<=t;j++)
    {
        q.push(v[j].s);
    }
    for(int i=b;i>=1;i--)
    {
        for(int k=1;k<=x&&!q.empty()&&q.top()<y[i];k++)
        {
            q.pop();
        }
    }
    return q.empty();
}
int main()
{
    scanf("%d%d%d",&a,&b,&t);
    for(int i=1;i<=a;i++)
    {
        scanf("%d",&x[i]);
    }
    for(int i=1;i<=b;i++)
    {
        scanf("%d",&y[i]);
    }
    for(int i=1;i<=t;i++)
    {
        scanf("%d%d",&v[i].w,&v[i].s);
    }
    sort(x+1,x+1+a);
    sort(y+1,y+1+b);
    sort(v+1,v+1+t);
    int l=1,r=t,best=-1;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            best=mid;
            r=mid-1;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d",best);
    return 0;
}
